/**
 * Searches for a phenotype by its description and returns the corresponding property name
 * @param {string} searchTerm - The phenotype description to search for
 * @returns {string|null} - The property name if found, null otherwise
 */
export function findPhenotypeByName(searchTerm) {
    if (!searchTerm || typeof searchTerm !== 'string') {
        return null;
    }

    // Normalize the search term (lowercase, trim whitespace)
    const normalizedSearch = searchTerm.toLowerCase().trim();

    // Search through the cfdePhenotypes object
    for (const [propertyName, description] of Object.entries(cfdePhenotypes)) {
        // Normalize the description for comparison
        const normalizedDescription = description.toLowerCase().trim();

        // Check for exact match
        if (normalizedDescription === normalizedSearch) {
            return propertyName;
        }

        // Check for partial match (contains)
        if (normalizedDescription.includes(normalizedSearch)) {
            return propertyName;
        }
    }

    return null;
}

export function findPhenotypeById(searchTerm) {
    if (!searchTerm || typeof searchTerm !== 'string') {
        return null;
    }

    // Search through the cfdePhenotypes object
    if (cfdePhenotypes[searchTerm]) {
        return cfdePhenotypes[searchTerm];
    }

    return null;
}

/**
 * Resolve a stored phenotype id to a user-facing label using CFDE maps only (human + mouse).
 * Does not consult API / description maps — use alongside those for full display formatting.
 * @param {string|number|null|undefined} phenotypeId
 * @returns {string|null}
 */
export function resolveCfdePhenotypeLabel(phenotypeId) {
    if (phenotypeId == null) return null;
    const idStr = String(phenotypeId).trim();
    if (!idStr) return null;
    if (cfdePhenotypes[idStr]) return cfdePhenotypes[idStr];
    if (cfdeMousePhenotypes[idStr]) return cfdeMousePhenotypes[idStr];
    return null;
}

/**
 * Human-readable gene-set cluster label for UI (Data / Results tables, pills, heatmap, network).
 * Resolves the hybrid **`label`** string (e.g. Orphanet_*, gcat_trait_*) via CFDE maps; if no mapping, returns the original string.
 * When the app falls back to **`factor_id`** as the cluster key, pass that string here too — it is resolved the same way when present in the maps.
 * @param {string|number|null|undefined} clusterLabelOrId - `label` from hybrid results, or `factor_id` when label is absent
 * @returns {string}
 */
export function resolveCfdeFactorClusterDisplayLabel(clusterLabelOrId) {
    const s = clusterLabelOrId != null ? String(clusterLabelOrId).trim() : "";
    if (!s) return "";
    const r = resolveCfdePhenotypeLabel(s);
    return r != null && String(r).trim() !== "" ? String(r).trim() : s;
}

export function getCfdePhenotypes() {
    return cfdePhenotypes;
}

export function getCfdeMousePhenotypes() {
    return cfdeMousePhenotypes;
}

export function getCfdePhenotypesInList() {
    return Object.keys(cfdePhenotypes).map(key => ({
        value: key,
        label: cfdePhenotypes[key]
    }));
}

export function getCfdeMousePhenotypesInList() {
    return Object.keys(cfdeMousePhenotypes).map(key => ({
        value: key,
        label: cfdeMousePhenotypes[key]
    }));
}

export default {
    findPhenotypeByName,
    findPhenotypeById,
    resolveCfdePhenotypeLabel,
    resolveCfdeFactorClusterDisplayLabel,
    getCfdePhenotypes,
    getCfdeMousePhenotypes,
    getCfdePhenotypesInList,
    getCfdeMousePhenotypesInList,
    cfdePhenotypes,
    cfdeMousePhenotypes,
};